import React, { useEffect, useState } from 'react';
import {
  ScatterChart, Scatter, XAxis, YAxis, CartesianGrid,
  Tooltip, ResponsiveContainer, Cell, ReferenceLine,
} from 'recharts';
import { getMoodMap } from '../api';

const COLORS = ['#1db954','#4fc3f7','#ffb400','#ce93d8','#ff6b6b','#80cbc4','#ffcc02','#f48fb1'];

const QUADRANTS = [
  { x: 0.75, y: 0.75, label: '⚡ Intense & Happy',    color: '#ffb400' },
  { x: 0.25, y: 0.75, label: '😌 Calm & Happy',       color: '#1db954' },
  { x: 0.25, y: 0.25, label: '😢 Calm & Sad',         color: '#4fc3f7' },
  { x: 0.75, y: 0.25, label: '😤 Intense & Sad',      color: '#ff6b6b' },
];

const CustomTooltip = ({ active, payload }) => {
  if (!active || !payload?.length) return null;
  const d = payload[0].payload;
  return (
    <div style={{
      background: '#1a1a1a',
      border: '1px solid rgba(255,255,255,0.1)',
      borderRadius: 10,
      padding: '12px 16px',
      fontSize: 13,
      minWidth: 160,
    }}>
      <p style={{ fontFamily: 'Syne, sans-serif', fontWeight: 700, marginBottom: 8, fontSize: 14 }}>
        {d.genre_group}
      </p>
      <p style={{ color: '#888', marginBottom: 3 }}>
        Energy: <span style={{ color: '#4fc3f7', fontWeight: 600 }}>{Number(d.avg_energy).toFixed(3)}</span>
      </p>
      <p style={{ color: '#888', marginBottom: 3 }}>
        Valence: <span style={{ color: '#ffb400', fontWeight: 600 }}>{Number(d.avg_valence).toFixed(3)}</span>
      </p>
      <p style={{ color: '#888' }}>
        Tracks: <span style={{ color: '#1db954', fontWeight: 600 }}>{Number(d.track_count).toLocaleString()}</span>
      </p>
    </div>
  );
};

const CustomDot = (props) => {
  const { cx, cy, payload, index } = props;
  const color = COLORS[index % COLORS.length];
  const r = Math.max(14, Math.min(28, (payload.track_count / 50000) * 10 + 14));
  return (
    <g>
      <circle cx={cx} cy={cy} r={r + 4} fill={color} opacity={0.15} />
      <circle cx={cx} cy={cy} r={r} fill={color} opacity={0.9} stroke="#0a0a0a" strokeWidth={2} />
      <text x={cx} y={cy + 4} textAnchor="middle" fill="#000" fontSize={10} fontWeight={700}
        fontFamily="DM Sans, sans-serif">
        {payload.genre_group.split('-')[0].substring(0, 4)}
      </text>
    </g>
  );
};

export default function MoodMap() {
  const [data,    setData]    = useState([]);
  const [loading, setLoading] = useState(true);
  const [error,   setError]   = useState(null);
  const [hovered, setHovered] = useState(null);

  useEffect(() => {
    getMoodMap()
      .then(d => { setData(d); setLoading(false); })
      .catch(e => { setError(e.message); setLoading(false); });
  }, []);

  if (loading) return <div className="loading"><div className="spinner" />Loading mood map...</div>;
  if (error)   return <div className="error">❌ {error}</div>;

  return (
    <div style={{ animation: 'fadeUp 0.5s ease' }}>
      <div className="page-header">
        <h1 className="page-title">Mood <span>Map</span></h1>
        <p className="page-sub">Where each genre lives emotionally — Energy (intensity) vs Valence (happiness)</p>
      </div>

      {/* Quadrant legend */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 10, marginBottom: '1.5rem' }}>
        {QUADRANTS.map(q => (
          <div key={q.label} style={{
            background: `${q.color}11`,
            border: `1px solid ${q.color}33`,
            borderRadius: 10,
            padding: '10px 14px',
            fontSize: 12,
            color: q.color,
            fontWeight: 500,
            textAlign: 'center',
          }}>
            {q.label}
          </div>
        ))}
      </div>

      {/* Main scatter chart */}
      <div className="chart-card" style={{ marginBottom: '1.5rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <div className="chart-title">Energy × Valence — Bubble size = track count</div>
          <div style={{ fontSize: 11, color: '#555', fontStyle: 'italic' }}>
            Hover over bubbles for details
          </div>
        </div>

        <ResponsiveContainer width="100%" height={420}>
          <ScatterChart margin={{ top: 20, right: 40, bottom: 40, left: 20 }}>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />

            {/* Quadrant dividers */}
            <ReferenceLine x={0.5} stroke="rgba(255,255,255,0.08)" strokeDasharray="6 4" />
            <ReferenceLine y={0.5} stroke="rgba(255,255,255,0.08)" strokeDasharray="6 4" />

            {/* Quadrant labels */}
            <ReferenceLine x={0.75} y={0.85} label={{ value: '⚡ Intense & Happy', fill: '#555', fontSize: 10 }} stroke="none" />
            <ReferenceLine x={0.15} y={0.85} label={{ value: '😌 Calm & Happy', fill: '#555', fontSize: 10 }} stroke="none" />
            <ReferenceLine x={0.15} y={0.15} label={{ value: '😢 Calm & Sad', fill: '#555', fontSize: 10 }} stroke="none" />
            <ReferenceLine x={0.75} y={0.15} label={{ value: '😤 Intense & Sad', fill: '#555', fontSize: 10 }} stroke="none" />

            <XAxis
              dataKey="avg_energy"
              type="number"
              domain={[0, 1]}
              name="Energy"
              tick={{ fill: '#666', fontSize: 12 }}
              tickCount={6}
              label={{ value: 'Energy (Intensity) →', position: 'insideBottom', offset: -20, fill: '#555', fontSize: 12 }}
            />
            <YAxis
              dataKey="avg_valence"
              type="number"
              domain={[0, 1]}
              name="Valence"
              tick={{ fill: '#666', fontSize: 12 }}
              tickCount={6}
              label={{ value: '← Sadness   Happiness →', angle: -90, position: 'insideLeft', offset: 10, fill: '#555', fontSize: 11 }}
            />
            <Tooltip content={<CustomTooltip />} />
            <Scatter data={data} shape={<CustomDot />}>
              {data.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
            </Scatter>
          </ScatterChart>
        </ResponsiveContainer>
      </div>

      {/* Genre cards grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 12 }}>
        {data.map((d, i) => (
          <div
            key={d.genre_group}
            className="card"
            style={{
              borderLeft: `3px solid ${COLORS[i % COLORS.length]}`,
              cursor: 'pointer',
              transition: '0.2s',
              transform: hovered === i ? 'translateY(-3px)' : 'none',
              boxShadow: hovered === i ? `0 8px 24px ${COLORS[i % COLORS.length]}22` : 'none',
            }}
            onMouseEnter={() => setHovered(i)}
            onMouseLeave={() => setHovered(null)}
          >
            <div style={{
              fontFamily: 'Syne, sans-serif', fontWeight: 700,
              fontSize: 14, marginBottom: 10,
              color: COLORS[i % COLORS.length],
            }}>
              {d.genre_group}
            </div>

            {[
              { label: 'Energy',   val: Number(d.avg_energy).toFixed(3),  pct: Number(d.avg_energy) },
              { label: 'Valence',  val: Number(d.avg_valence).toFixed(3), pct: Number(d.avg_valence) },
            ].map(row => (
              <div key={row.label} style={{ marginBottom: 8 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, marginBottom: 3 }}>
                  <span style={{ color: '#888' }}>{row.label}</span>
                  <span style={{ color: COLORS[i % COLORS.length], fontWeight: 500 }}>{row.val}</span>
                </div>
                <div style={{ height: 4, background: 'rgba(255,255,255,0.06)', borderRadius: 2, overflow: 'hidden' }}>
                  <div style={{
                    height: '100%',
                    width: `${row.pct * 100}%`,
                    background: COLORS[i % COLORS.length],
                    borderRadius: 2,
                    transition: '0.4s ease',
                  }} />
                </div>
              </div>
            ))}

            <div style={{ fontSize: 11, color: '#555', marginTop: 6, textAlign: 'right' }}>
              {Number(d.track_count).toLocaleString()} tracks
            </div>
          </div>
        ))}
      </div>

      <style>{`
        @keyframes fadeUp {
          from { opacity:0; transform:translateY(12px); }
          to   { opacity:1; transform:translateY(0); }
        }
      `}</style>
    </div>
  );
}
